const now = new Date();
const periodStart = new Date(now.getFullYear(), now.getMonth(), 1);
const periodEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0);
const paymentDate = new Date(now.getFullYear(), now.getMonth() + 1, 5);
return [{
  json: {
    period_start: periodStart.toISOString().split('T')[0],
    period_end: periodEnd.toISOString().split('T')[0],
    payment_date: paymentDate.toISOString().split('T')[0]
  }
}];

const period = $('Set Period').first().json;
const rows = $input.first().json;
const list = Array.isArray(rows) ? rows : [];
if (!list.length) {
  throw new Error('No active employee found — seed DB first.');
}
const e = list[0];
return [{ json: {
  employee_id: e.id,
  first_name: e.first_name,
  last_name: e.last_name,
  personnel_number: e.personnel_number,
  period_start: period.period_start,
  period_end: period.period_end,
  payment_date: period.payment_date
} }];

const ctx = $('Pick Employee + Period').first().json;
const raw = $input.first().json;
const row = Array.isArray(raw) ? raw[0] : raw;
if (!row || row.gross_salary == null) {
  throw new Error('RPC returned no payroll row');
}
return [{
  json: {
    employee_id: ctx.employee_id,
    first_name: ctx.first_name,
    last_name: ctx.last_name,
    personnel_number: ctx.personnel_number,
    period_start: ctx.period_start,
    period_end: ctx.period_end,
    payment_date: ctx.payment_date,
    gross_salary: row.gross_salary,
    tax_deduction: row.tax_deduction,
    social_security: row.social_security,
    net_salary: row.net_salary
  }
}];

